const now = new Date();
const day = now.getDay();
const weekNum = Math.ceil((now - new Date(now.getFullYear(), 0, 1)) / 604800000);
const emotions = ['Relief', 'Frustration', 'Aspiration', 'Humor'];
const emotion = emotions[day % 4];
return [{ json: { day, weekNum, emotion, timestamp: now.toISOString() } }];

const dayData = $('Calculate Day & Week').first().json;
const allBucket = $('Get Content Bucket').all().map(i => i.json);
const pillars = $('Get Content Pillars').all().map(i => i.json);

const { emotion, day, weekNum } = dayData;

const sortByLastUsed = (arr) => [...arr].sort((a, b) => {
  const aDate = a.property_last_used_date?.start || null;
  const bDate = b.property_last_used_date?.start || null;
  if (!aDate && !bDate) return 0;
  if (!aDate) return -1;
  if (!bDate) return 1;
  return new Date(aDate) - new Date(bDate);
});

const bucket = sortByLastUsed(allBucket);

const tofuPillars = pillars.filter(p => p.property_funnel_stage === 'TOFU');
const mofuPillars = pillars.filter(p => p.property_funnel_stage === 'MOFU');
const bofuPillars = pillars.filter(p => p.property_funnel_stage === 'BOFU');

// Rotate through all 4 TOFU pillars — pick 2 consecutive
const tofuPillar1 = tofuPillars[day % tofuPillars.length] || tofuPillars[0] || {};
const tofuPillar2 = tofuPillars[(day + 1) % tofuPillars.length] || tofuPillars[0] || {};

// Rotate through all 4 MOFU pillars — pick 2 consecutive
const mofuPillar1 = mofuPillars[day % mofuPillars.length] || mofuPillars[0] || {};
const mofuPillar2 = mofuPillars[(day + 1) % mofuPillars.length] || mofuPillars[0] || {};

// BOFU — single pillar, rotates if more added later
const bofuPillar1 = bofuPillars[day % bofuPillars.length] || bofuPillars[0] || {};

const getName = (item) => item && (item.name || item.property_pillar_name || item.property_name || 'Untitled');
const getSourceUrl = (item) => item && (item.property_url || item.property_reel_url || item.url || '');
const getSummary = (item) => item && (item.property_summary || item.property_hook || item.name || '');
const getPillarName = (item) => item && (item.property_pillar_name || item.name || 'Content Pillar');
const getPillarCtx = (p) => 'Pillar: ' + getPillarName(p) + '\nEmotion Theme: ' + (p.property_emotion_theme || '') + '\nTalk About: ' + (p.property_talk_about || '').slice(0, 300) + '\nFormat Hint: ' + (p.property_format_hint || '');

const INSPIRATION_RULE = '\n\nCONTENT RULES:\n- Use TOPIC and ANGLE as inspiration only. Write original content in {{CLIENT_FIRST_NAME}}\'s voice. Do NOT copy hook, structure, or specific examples.\n- Never lift sentences or specific examples from source.';

const PLAIN_LANGUAGE = '\n\nLANGUAGE RULES:\n- Write at 5th grade level. No jargon, no tech terms without plain-English explanation.\n- Normal people and beginners must understand every sentence.\n- Follow CTA: follow @inboundos';

const JSON_SUFFIX = '\n\nOUTPUT: Respond with ONLY a raw JSON object, no markdown, no fences:\n{"script_title":"","hook":"","body_structure":[],"cta":"","format":"","tone":"","emotional_trigger":"","topics":[],"caption":""}';

const scripts = [
  {
    script_number: 1,
    funnel_stage: 'TOFU',
    source_type: 'Content Pillar',
    source_title: getPillarName(tofuPillar1),
    source_id: (tofuPillar1 && tofuPillar1.id) || '',
    source_url: '',
    emotion, weekNum,
    cta_type: 'Engagement',
    pillar: getPillarName(tofuPillar1),
    prompt: 'Write a TOFU social media tips reel for {{CLIENT_FIRST_NAME}} Cruz.\n\nFORMAT:\n- hook: Specific, surprising, or uncomfortable. Max 8 words. No generic openers.\n- body_structure: 3-4 short teaching points. One sentence per line. Max 6-8 words per line. Teleprompter format. Blank line every 2-3 lines.\n- tone: Direct, founder-to-founder. No fluff.\n- cta: save this / follow for more\n\n' + getPillarCtx(tofuPillar1) + '\nEmotion: ' + emotion + PLAIN_LANGUAGE + JSON_SUFFIX
  },
  {
    script_number: 2,
    funnel_stage: 'TOFU',
    source_type: 'Content Pillar',
    source_title: getPillarName(tofuPillar2),
    source_id: (tofuPillar2 && tofuPillar2.id) || '',
    source_url: '',
    emotion, weekNum,
    cta_type: 'Engagement',
    pillar: getPillarName(tofuPillar2),
    prompt: 'Write a TOFU Read Caption reel for {{CLIENT_FIRST_NAME}} Cruz.\n\nFORMAT:\n- hook: Short belief-reframe max 10 words ending with ".." then "(Read caption)"\n- body_structure: 5-7 short punchy paragraphs as the caption. Structure: wrong belief → root cause → contrast → real insight → identity shift. Max 6-8 words per line.\n- caption: body_structure joined as one string\n- format: Read Caption (7-second video)\n- tone: Direct, contrarian, founder-to-founder\n- cta: follow @inboundos if you want inbound leads without cold outreach\n\n' + getPillarCtx(tofuPillar2) + '\nEmotion: ' + emotion + PLAIN_LANGUAGE + JSON_SUFFIX
  },
  {
    script_number: 3,
    funnel_stage: 'MOFU',
    source_type: 'Content Bucket + Pillar',
    source_title: getName(bucket[0]),
    source_id: (bucket[0] && bucket[0].id) || '',
    source_url: getSourceUrl(bucket[0]),
    emotion, weekNum,
    cta_type: 'Lead',
    pillar: getPillarName(mofuPillar1),
    prompt: 'MOFU system breakdown reel for {{CLIENT_FIRST_NAME}} Cruz. Use source as inspiration only — write in {{CLIENT_FIRST_NAME}}\'s original voice.' + INSPIRATION_RULE + '\n\nSource: ' + getName(bucket[0]) + '\nHook: ' + getSummary(bucket[0]).slice(0, 300) + '\n\n' + getPillarCtx(mofuPillar1) + '\nEmotion: ' + emotion + '\nGoal: Shift belief from skill gap to system gap.\n\nFORMAT:\n- hook: Hook their frustration. Specific and uncomfortable.\n- body_structure: Hook → Problem → Why the usual fix fails → The system → CTA. Short lines, max 6-8 words, teleprompter format.\n- cta: DM or book a call' + PLAIN_LANGUAGE + JSON_SUFFIX
  },
  {
    script_number: 4,
    funnel_stage: 'MOFU',
    source_type: 'Content Bucket + Pillar',
    source_title: getName(bucket[1] || bucket[0]),
    source_id: ((bucket[1] || bucket[0]) && (bucket[1] || bucket[0]).id) || '',
    source_url: getSourceUrl(bucket[1] || bucket[0]),
    emotion, weekNum,
    cta_type: 'Lead',
    pillar: getPillarName(mofuPillar2),
    prompt: 'MOFU system breakdown reel for {{CLIENT_FIRST_NAME}} Cruz. Use source as inspiration only — write in {{CLIENT_FIRST_NAME}}\'s original voice.' + INSPIRATION_RULE + '\n\nSource: ' + getName(bucket[1] || bucket[0]) + '\nHook: ' + getSummary(bucket[1] || bucket[0]).slice(0, 300) + '\n\n' + getPillarCtx(mofuPillar2) + '\nEmotion: ' + emotion + '\nGoal: Shift belief from skill gap to system gap.\n\nFORMAT:\n- hook: Hook their frustration. Specific and uncomfortable.\n- body_structure: Hook → Problem → Why the usual fix fails → The system → CTA. Short lines, max 6-8 words, teleprompter format.\n- cta: DM or book a call' + PLAIN_LANGUAGE + JSON_SUFFIX
  },
  {
    script_number: 5,
    funnel_stage: 'BOFU',
    source_type: 'Content Pillar',
    source_title: getPillarName(bofuPillar1),
    source_id: (bofuPillar1 && bofuPillar1.id) || '',
    source_url: '',
    emotion, weekNum,
    cta_type: 'Close',
    pillar: getPillarName(bofuPillar1),
    prompt: 'BOFU conversion reel for {{CLIENT_FIRST_NAME}} Cruz. Direct and proof-driven. No hype.\n\nFORMAT:\n- hook: A specific result or outcome from InboundOS install. Max 8 words.\n- body_structure: What the install includes → what client gets → timeline → one real result. Short lines, max 6-8 words, teleprompter format.\n- tone: Direct, specific, no hype, no superlatives\n- cta: Link in bio to apply / DM "install"\n\n' + getPillarCtx(bofuPillar1) + '\nEmotion: ' + emotion + PLAIN_LANGUAGE + JSON_SUFFIX
  }
];

return scripts.map(s => ({ json: s }));

const raw = $input.first().json.text || $input.first().json.content || '';

function tryParse(str) {
  try { return JSON.parse(str); } catch(e) { return null; }
}

function repairJson(str) {
  // Try progressively shorter strings ending at last }
  let s = str;
  for (let i = s.length - 1; i > 0; i--) {
    if (s[i] === '}') {
      const attempt = tryParse(s.slice(0, i + 1));
      if (attempt) return attempt;
    }
  }
  return null;
}

let parsed = {};
let parse_error = null;

try {
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  const jsonStr = fenced ? fenced[1].trim() : raw.match(/\{[\s\S]*\}/)?.[0];
  if (!jsonStr) {
    parsed = { parse_error: 'no JSON found', raw_preview: raw.slice(0, 500) };
  } else {
    const direct = tryParse(jsonStr);
    if (direct) {
      parsed = direct;
    } else {
      // truncated JSON — repair by finding last valid closing brace
      const repaired = repairJson(jsonStr);
      if (repaired) {
        parsed = repaired;
        parsed._repaired = true;
      } else {
        parsed = { parse_error: 'JSON unrecoverable', raw_preview: raw.slice(0, 500) };
      }
    }
  }
} catch(e) {
  parsed = { parse_error: e.message, raw_preview: raw.slice(0, 500) };
}

const meta = $('Split In Batches').first().json;

const body = Array.isArray(parsed.body_structure)
  ? parsed.body_structure.map(item => typeof item === 'string' ? item : (item.text || item.content || JSON.stringify(item))).join('\n')
  : (parsed.body_structure || '');
const script = body + (parsed.cta ? '\n\nCTA: ' + parsed.cta : '');
const caption = parsed.caption || ((parsed.hook || '') + (parsed.cta ? '\n\n' + parsed.cta : ''));

const finalScript = meta.script_override !== undefined ? meta.script_override : script;
return [{ json: { ...meta, ...parsed, script: finalScript, caption } }];

